MERGE INTO CONSULTAS FIN USING (SELECT '002053AlmacenContabilidadSIIF' INFORME ,TO_CLOB(q'[SELECT 's$consecutivo$s' "Consecutivo", 's$fechaContable$s' "Fecha Contable", 's$tipoDocumento$s' "Tipo de Documento", 's$numeroDocumento$s' "Numero Documento", 's$descripcion$s' "Descripción Transacción" 
FROM DUAL]') CONSULTA, 10 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);